final:
module shift_register_8bit(
    input [7:0] data_in,
    input clk,
    input load,
    output reg data_out
);

reg [7:0] obf_shift_reg;

always @(posedge clk) begin
    if (load)
        obf_shift_reg <= data_in;
    else
        obf_shift_reg <= {obf_shift_reg[6:0], 1'b0};
end

always @(posedge clk) begin
    data_out <= obf_shift_reg[7];
end

endmodule
